{"title":"OpAMP heap allocation","type":"vega","params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "autosize": {
    "type": "fit",
    "contains": "padding"
  },
  "padding": 5,
  "data": [
    {
      "name": "table",
      "url": {
        "%context%": true,
        "%timefield%": "@timestamp",
        "index": "metrics-opamp.server-*",
        "body": {
          "size": 0,
          "aggs": {
            "times": {
              "date_histogram": {
                "field": "@timestamp",
                "fixed_interval": "30s"
              },
              "aggs": {
                "value": {
                  "max": {
                    "field": "server.heap_alloc_bytes"
                  }
                }
              }
            }
          }
        }
      },
      "format": {
        "property": "aggregations.times.buckets"
      }
    }
  ],
  "scales": [
    {
      "name": "x",
      "type": "time",
      "domain": {
        "data": "table",
        "field": "key"
      },
      "range": "width"
    },
    {
      "name": "y",
      "type": "linear",
      "domain": {
        "data": "table",
        "field": "value.value"
      },
      "nice": true,
      "zero": true,
      "range": "height"
    }
  ],
  "axes": [
    {
      "orient": "bottom",
      "scale": "x",
      "title": "Time"
    },
    {
      "orient": "left",
      "scale": "y",
      "title": "Heap alloc bytes"
    }
  ],
  "marks": [
    {
      "type": "line",
      "from": {
        "data": "table"
      },
      "encode": {
        "enter": {
          "stroke": {
            "value": "#36a2ef"
          },
          "strokeWidth": {
            "value": 2
          }
        },
        "update": {
          "x": {
            "scale": "x",
            "field": "key"
          },
          "y": {
            "scale": "y",
            "field": "value.value"
          }
        }
      }
    }
  ]
}"}}

